    bool isBoomerang(vector<vector<int>>& points) {
        int n = points.size();
        if (n != 3) return false;

        vector<int> xDist(3, 0);
        vector<int> yDist(3, 0);

        for (int i = 0; i < n; i++) {
            xDist[i] = points[i][0] - points[(i + 1) % 3][0];
            yDist[i] = points[i][1] - points[(i + 1) % 3][1];
        }

        return checkBoomerang(points[0], points[1], points[2]);
    }

    bool checkBoomerang(int x1, int y1, int x2) {
        return abs(x2 - x1) * abs(y2 - y1) == abs(x1 - x2) * abs(y1 - y2);
    }
};
